import React, { useState } from 'react';

const TaskCard = ({ task, users = [], projects = [], onStatusChange, onEdit, onDelete }) => {
  const [currentTask, setCurrentTask] = useState(task);
  const assignee = users.find(user => user.id === currentTask.assignee_id) || {};
  const project = projects.find(proj => proj.id === currentTask.project_id) || {};

  const getStatusColor = (status) => {
    switch (status) {
      case 'Completed': return '#2ecc71';
      case 'In Progress': return '#f39c12';
      default: return '#95a5a6';
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'No due date';
    const options = { year: 'numeric', month: '2-digit', day: '2-digit' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  const handleStatusChange = (e) => {
    const newStatus = e.target.value;
    setCurrentTask(prev => ({ ...prev, status: newStatus }));
    if (onStatusChange) {
      onStatusChange(task.id, newStatus);
    }
  };

  const handleEdit = (e) => {
    e.stopPropagation();
    if (onEdit) onEdit(task);
  };

  const handleDelete = (e) => {
    e.stopPropagation();
    if (onDelete && window.confirm('Are you sure you want to delete this task?')) {
      onDelete(task.id);
    }
  };

  return (
    <div className="task-card">
      <div className="task-header">
        <h3 className="task-title">{currentTask.title}</h3>
        <div className="task-status">
          <select 
            value={currentTask.status}
            onChange={handleStatusChange}
            className="status-select"
            style={{ 
              borderColor: getStatusColor(currentTask.status),
              color: getStatusColor(currentTask.status)
            }}
          >
            <option value="Not Started">Not Started</option>
            <option value="In Progress">In Progress</option>
            <option value="Completed">Completed</option>
          </select>
        </div>
      </div>

      {currentTask.description && (
        <p className="task-description">{currentTask.description}</p>
      )}

      <div className="task-meta">
        {project && (
          <div className="meta-item">
            <span className="meta-label">Project:</span>
            <span className="meta-value" style={{ color: project.color || '#3498db' }}>
              {project.name || 'No project'}
            </span>
          </div>
        )}

        {assignee && (
          <div className="meta-item">
            <span className="meta-label">Assignee:</span>
            <span className="meta-value">
              {assignee.name || 'Unassigned'}
            </span>
          </div>
        )}

        <div className="meta-item">
          <span className="meta-label">Due:</span>
          <span className="meta-value">
            {formatDate(currentTask.due_date)}
          </span>
        </div>
      </div>

      <div className="task-actions">
        <button 
          className="btn btn-edit"
          onClick={handleEdit}
        >
          Edit
        </button>
        <button 
          className="btn btn-danger"
          onClick={handleDelete}
        >
          Delete
        </button>
      </div>
    </div>
  );
};

export default TaskCard;
